    limitInfo.lastAttempt = now;

    if (limitInfo.attempts >= 5) {
      // Lock the account for escalating periods
      limitInfo.lockedUntil = now + [60000, 300000, 900000][Math.min(2, Math.floor((limitInfo.attempts - 1) / 5))];
